1	import * as vscode from "vscode";
2	import { spawn, ChildProcess } from "child_process";
3	import { watch, FSWatcher, existsSync, readFileSync } from "fs";
4	import { join, resolve, dirname, basename } from "path";
5	import { fileURLToPath } from "url";
6	import { homedir } from "os";
7	import { get as httpGet, request as httpRequest } from "http";
8	import { execFileSync, execFile } from "child_process";
9	import { promisify } from "util";
10	import { SessionDetailPanel } from "./SessionDetailPanel.js";
11	import { openCheckpointDiff } from "./diffUtils.js";
12	import { CheckpointTreeProvider } from "./CheckpointTreeProvider.js";
13	
14	const execFileAsync = promisify(execFile);
15	
16	const __dirname = dirname(fileURLToPath(import.meta.url));
17	
18	// Path to the gossamer server entry point.
19	// Packaged VSIX: bundled-server/serve.js lives inside the extension directory.
20	// Dev mode (gossamer-testing): fall back to the repo's compiled dist/serve.js.
21	const BUNDLED_SERVE = resolve(__dirname, "../bundled-server/serve.js");
22	const DEV_SERVE     = resolve(__dirname, "../../../dist/serve.js");
23	const SERVE_SCRIPT  = existsSync(BUNDLED_SERVE) ? BUNDLED_SERVE : DEV_SERVE;
24	
25	// Maps the agent name (from CheckpointSessionMetadata.agent) to its CLI command.
26	export const AGENT_CLI: Record<string, { bin: string; resumeFlag: string; renameCmd?: string }> = {
27	  "Claude Code": { bin: "claude",  resumeFlag: "--resume", renameCmd: "/rename" },
28	  "Gemini CLI":  { bin: "gemini",  resumeFlag: "--resume" },
29	  "Codex":       { bin: "codex",   resumeFlag: "--session" },
30	};
31	const DEFAULT_AGENT_CLI = AGENT_CLI["Claude Code"];
32	
33	// Use the system node, not VS Code's bundled Electron node
34	function getSystemNode(): string {
35	  try {
36	    return execFileSync("which", ["node"], { encoding: "utf8" }).trim();
37	  } catch {
38	    return "node"; // fall back to PATH lookup
39	  }
40	}
41	
42	/** Probe the server once; resolves true if it responds, false otherwise. */
43	function probeServer(port: number): Promise<boolean> {
44	  return new Promise((resolve) => {
45	    const req = httpGet(`http://localhost:${port}/api/sessions`, (res) => {
46	      res.destroy();
47	      resolve(true);
48	    });
49	    req.on("error", () => resolve(false));
50	    req.setTimeout(500, () => { req.destroy(); resolve(false); });
51	  });
52	}
53	
54	/** Poll until the server responds or we time out (default 30s). */
55	async function waitForServer(port: number, timeoutMs = 30_000): Promise<void> {
56	  const deadline = Date.now() + timeoutMs;
57	  while (Date.now() < deadline) {
58	    if (await probeServer(port)) return;
59	    await new Promise((r) => setTimeout(r, 500));
60	  }
61	  throw new Error("Gossamer server did not start within 30s");
62	}
63	
64	const DEFAULT_PORT = 3456;
65	
66	function getConfiguredPort(): number {
67	  try {
68	    const raw = readFileSync(join(homedir(), ".gossamer", "config.json"), "utf8");
69	    const cfg = JSON.parse(raw) as { port?: number };
70	    return typeof cfg.port === "number" ? cfg.port : DEFAULT_PORT;
71	  } catch {
72	    return DEFAULT_PORT;
73	  }
74	}
75	
76	function httpGetJson<T>(url: string): Promise<T> {
77	  return new Promise((resolve, reject) => {
78	    const req = httpGet(url, (res) => {
79	      const chunks: Buffer[] = [];
80	      res.on("data", (c: Buffer) => chunks.push(c));
81	      res.on("end", () => {
82	        try { resolve(JSON.parse(Buffer.concat(chunks).toString("utf8")) as T); }
83	        catch (e) { reject(e); }
84	      });
85	    });
86	    req.on("error", reject);
87	    req.setTimeout(5000, () => { req.destroy(); reject(new Error("timeout")); });
88	  });
89	}
90	
91	function httpPostJson<T>(url: string, body: unknown): Promise<T> {
92	  return new Promise((resolve, reject) => {
93	    const data = JSON.stringify(body);
94	    const opts = new URL(url);
95	    const req = httpRequest({
96	      hostname: opts.hostname,
97	      port: opts.port,
98	      path: opts.pathname,
99	      method: "POST",
100	      headers: { "Content-Type": "application/json", "Content-Length": Buffer.byteLength(data) },
101	    }, (res) => {
102	      const chunks: Buffer[] = [];
103	      res.on("data", (c: Buffer) => chunks.push(c));
104	      res.on("end", () => {
105	        try { resolve(JSON.parse(Buffer.concat(chunks).toString("utf8")) as T); }
106	        catch (e) { reject(e); }
107	      });
108	    });
109	    req.on("error", reject);
110	    req.write(data);
111	    req.end();
112	  });
113	}
