115	export class GossamerPanel {
116	  private static instance: GossamerPanel | undefined;
117	
118	  // Server is static so it survives panel disposal (minimize/restore)
119	  private static server: ChildProcess | undefined;
120	  private static serverPort: number | undefined;
121	
122	  private readonly panel: vscode.WebviewPanel;
123	  private readonly context: vscode.ExtensionContext;
124	  private readonly repoPath: string;
125	  private readonly port: number;
126	  private readonly checkpointProvider: CheckpointTreeProvider;
127	  private watcher: FSWatcher | undefined;
128	  private disposables: vscode.Disposable[] = [];
129	  private serverReady = false;
130	
131	  static async createOrShow(context: vscode.ExtensionContext, repoPath: string, checkpointProvider: CheckpointTreeProvider) {
132	    if (GossamerPanel.instance) {
133	      GossamerPanel.instance.panel.reveal();
134	      return;
135	    }
136	    const port = getConfiguredPort();
137	    GossamerPanel.instance = new GossamerPanel(context, repoPath, port, checkpointProvider);
138	  }
139	
140	  /** Hide the panel without killing the server (minimizes to nothing; re-open via command). */
141	  static minimize() {
142	    if (!GossamerPanel.instance) return;
143	    // Dispose the webview only — server stays alive
144	    GossamerPanel.instance.disposeWebviewOnly();
145	  }
146	
147	  /** Toggle: minimize if visible, restore if hidden. */
148	  static toggle(context: vscode.ExtensionContext, repoPath: string, checkpointProvider: CheckpointTreeProvider) {
149	    if (GossamerPanel.instance) {
150	      GossamerPanel.minimize();
151	    } else {
152	      GossamerPanel.createOrShow(context, repoPath, checkpointProvider).catch(console.error);
153	    }
154	  }
155	
156	  /** Kill and restart the server process, then re-signal the panel when ready. */
157	  static restart(repoPath: string) {
158	    const port = getConfiguredPort();
159	    GossamerPanel.server?.kill();
160	    GossamerPanel.server = undefined;
161	    GossamerPanel.serverPort = undefined;
162	    const instance = GossamerPanel.instance;
163	    if (instance) {
164	      instance.serverReady = false;
165	      instance.spawnServer();
166	      waitForServer(port)
167	        .then(() => instance.ensureRepoRegistered())
168	        .then(() => {
169	          instance.serverReady = true;
170	          instance.panel.webview.postMessage({ type: "server_ready" });
171	        })
172	        .catch((err) => instance.panel.webview.postMessage({ type: "server_error", error: String(err) }));
173	    } else {
174	      const nodeExec = getSystemNode();
175	      if (existsSync(SERVE_SCRIPT)) {
176	        const proc = spawn(nodeExec, [SERVE_SCRIPT, "--repo-dir", repoPath, "--port", String(port)], {
177	          stdio: ["ignore", "pipe", "pipe"],
178	          env: { ...process.env, FORCE_COLOR: "0" },
179	        });
180	        proc.on("exit", () => { if (GossamerPanel.server === proc) { GossamerPanel.server = undefined; GossamerPanel.serverPort = undefined; } });
181	        GossamerPanel.server = proc;
182	        GossamerPanel.serverPort = port;
183	      }
184	    }
185	  }
186	
187	  /** Full shutdown — kills server too (called on extension deactivate). */
188	  static dispose() {
189	    GossamerPanel.instance?.cleanup(true);
190	    GossamerPanel.instance = undefined;
191	  }
192	
193	  static searchSessions() {
194	    GossamerPanel.instance?.openSearchQuickPick().catch(console.error);
195	  }
196	
197	  private constructor(context: vscode.ExtensionContext, repoPath: string, port: number, checkpointProvider: CheckpointTreeProvider) {
198	    this.context            = context;
199	    this.repoPath           = repoPath;
200	    this.port               = port;
201	    this.checkpointProvider = checkpointProvider;
202	
203	    this.panel = vscode.window.createWebviewPanel(
204	      "gossamer",
205	      "Gossamer",
206	      vscode.ViewColumn.Two,
207	      {
208	        enableScripts: true,
209	        enableFindWidget: true,
210	        retainContextWhenHidden: true,
211	        localResourceRoots: [
212	          vscode.Uri.joinPath(context.extensionUri, "dist", "webview"),
213	        ],
214	      },
215	    );
216	
217	    this.spawnServer();
218	    this.panel.webview.html = this.getWebviewHtml(context);
219	    this.panel.onDidDispose(() => this.cleanup(false), undefined, this.disposables);
220	    this.panel.webview.onDidReceiveMessage(
221	      (msg: { type: string; sessionId?: string; title?: string; checkpointId?: string; filePath?: string }) => {
222	        if (msg.type === "open_session" && msg.sessionId) {
223	          SessionDetailPanel.createOrShow(this.context, msg.sessionId, msg.title ?? msg.sessionId.slice(0, 8), this.port, this.checkpointProvider);
224	        }
225	        if (msg.type === "show_checkpoint_diff" && msg.checkpointId && msg.filePath) {
226	          openCheckpointDiff(this.port, msg.checkpointId, msg.filePath).catch(console.error);
227	        }
228	        if (msg.type === "new_session") {
229	          this.promptAndSpawnSession().catch(console.error);
230	        }
231	        if (msg.type === "search_sessions") {
232	          this.openSearchQuickPick().catch(console.error);
233	        }
234	        if (msg.type === "minimize") {
235	          GossamerPanel.minimize();
236	        }
237	      },
238	      undefined,
239	      this.disposables,
240	    );
241	    this.watchGitBranch();
242	
243	    // Signal the webview once the server is accepting requests.
244	    // Also re-signal on visibility changes (e.g. tab moved to a new window causes a reload).
245	    this.panel.onDidChangeViewState(
246	      (e) => { if (e.webviewPanel.visible && this.serverReady) this.panel.webview.postMessage({ type: "server_ready" }); },
247	      undefined,
248	      this.disposables,
249	    );
250	    waitForServer(this.port)
251	      .then(() => this.ensureRepoRegistered())
252	      .then(() => { this.serverReady = true; return this.panel.webview.postMessage({ type: "server_ready" }); })
253	      .catch((err) => this.panel.webview.postMessage({ type: "server_error", error: String(err) }));
254	  }
255	
256	  private spawnServer() {
257	    // Reuse existing static server if already running on the same port
258	    if (GossamerPanel.server && GossamerPanel.serverPort === this.port) {
259	      console.log("[Gossamer] reusing existing server on port", this.port);
260	      return;
261	    }
262	
263	    if (!existsSync(SERVE_SCRIPT)) {
264	      const msg = `Gossamer server script not found at ${SERVE_SCRIPT}. Run \`npm run build\` in the gossamer repo root first.`;
265	      console.error("[Gossamer]", msg);
266	      vscode.window.showErrorMessage(msg);
267	      return;
268	    }
269	
270	    const nodeExec = getSystemNode();
271	    console.log(`[Gossamer] spawning: ${nodeExec} ${SERVE_SCRIPT} --repo-dir ${this.repoPath} --port ${this.port}`);
272	
273	    const proc = spawn(nodeExec, [SERVE_SCRIPT, "--repo-dir", this.repoPath, "--port", String(this.port)], {
274	      stdio: ["ignore", "pipe", "pipe"],
275	      env: { ...process.env, FORCE_COLOR: "0" },
276	    });
277	
278	    proc.stdout?.on("data", (d: Buffer) => {
279	      console.log("[Gossamer server stdout]", d.toString().trim());
280	    });
281	    proc.stderr?.on("data", (d: Buffer) => {
282	      console.error("[Gossamer server stderr]", d.toString().trim());
283	    });
284	    proc.on("error", (err) => {
285	      console.error("[Gossamer] failed to spawn server:", err.message);
286	      vscode.window.showErrorMessage(`Gossamer: failed to start server — ${err.message}`);
287	    });
288	    proc.on("exit", (code, signal) => {
289	      console.log(`[Gossamer server] exited code=${code} signal=${signal}`);
290	      if (GossamerPanel.server === proc) {
291	        GossamerPanel.server = undefined;
292	        GossamerPanel.serverPort = undefined;
293	      }
294	    });
295	
296	    GossamerPanel.server = proc;
297	    GossamerPanel.serverPort = this.port;
298	  }
299	
300	  private async openSearchQuickPick(): Promise<void> {
301	    interface SessionData {
302	      sessionId: string;
303	      intent: string | null;
304	      prompt: string | null;
305	      repoName: string | null;
306	      cwd: string;
307	      slug?: string | null;
308	      customTitle?: string | null;
309	    }
310	    interface ContentResult {
311	      sessionId: string;
312	      snippet: string;
313	      contentType: string;
314	    }
315	    type QP = vscode.QuickPickItem & { sessionId: string; sessionTitle: string };
316	
317	    const allSessions = await httpGetJson<SessionData[]>(`http://localhost:${this.port}/api/sessions`);
318	
319	    const sessionLabel = (s: SessionData) =>
320	      s.intent ?? s.prompt?.slice(0, 80) ?? s.customTitle ?? s.slug ?? s.sessionId.slice(0, 8) ?? "";
321	
322	    const toSessionItem = (s: SessionData): QP => ({
323	      sessionId:    s.sessionId,
324	      sessionTitle: sessionLabel(s),
325	      label:        sessionLabel(s),
326	      description:  s.repoName ?? s.cwd.split("/").pop() ?? "",
327	      detail:       s.cwd,
328	    });
329	
330	    const buildItems = (query: string, contentResults: ContentResult[]): QP[] => {
331	      const q = query.toLowerCase();
332	      const sessionMatches = query
333	        ? allSessions.filter((s) =>
334	            sessionLabel(s).toLowerCase().includes(q) ||
335	            (s.repoName ?? "").toLowerCase().includes(q) ||
336	            s.cwd.toLowerCase().includes(q),
337	          )
338	        : allSessions;
339	
340	      const items: QP[] = [];
341	
342	      if (sessionMatches.length > 0) {
343	        if (contentResults.length > 0) {
344	          items.push({ kind: vscode.QuickPickItemKind.Separator, label: "Sessions", sessionId: "", sessionTitle: "" });
345	        }
346	        items.push(...sessionMatches.map(toSessionItem));
347	      }
348	
349	      if (contentResults.length > 0) {
350	        const seenInSessions = new Set(sessionMatches.map((s) => s.sessionId));
351	        items.push({ kind: vscode.QuickPickItemKind.Separator, label: "Chat History", sessionId: "", sessionTitle: "" });
352	        for (const r of contentResults) {
353	          const session = allSessions.find((s) => s.sessionId === r.sessionId);
354	          const sLabel  = sessionLabel(session ?? { sessionId: r.sessionId, intent: null, prompt: null, repoName: null, cwd: "", slug: null });
355	          const snippet = r.snippet.replace(/«/g, "").replace(/»/g, "").trim();
356	          items.push({
357	            sessionId:    r.sessionId,
358	            sessionTitle: sLabel,
359	            label:        snippet || sLabel,
360	            description:  sLabel,
361	            detail:       session?.cwd ?? "",
362	            alwaysShow:   true,
363	          });
364	        }
365	      }
366	
367	      return items;
368	    };
369	
370	    const qp = vscode.window.createQuickPick<QP>();
371	    qp.placeholder = "Search sessions and chat history…";
372	    qp.matchOnDescription = false;
373	    qp.matchOnDetail = false;
374	    qp.items = allSessions.map(toSessionItem);
375	
376	    let debounce: ReturnType<typeof setTimeout> | undefined;
377	
378	    qp.onDidChangeValue((query) => {
379	      if (debounce) clearTimeout(debounce);
380	      if (!query.trim()) {
381	        qp.busy = false;
382	        qp.items = allSessions.map(toSessionItem);
383	        return;
384	      }
385	      qp.busy = true;
386	      debounce = setTimeout(async () => {
387	        let contentResults: ContentResult[] = [];
388	        try {
389	          contentResults = await httpGetJson<ContentResult[]>(
390	            `http://localhost:${this.port}/api/search?q=${encodeURIComponent(query)}&limit=20`,
391	          );
392	        } catch { /* FTS syntax error — show session matches only */ }
393	        qp.items = buildItems(query, contentResults);
394	        qp.busy = false;
395	      }, 300);
396	    });
397	
398	    qp.onDidAccept(() => {
399	      const selected = qp.selectedItems[0];
400	      const query = qp.value.trim();
401	      qp.dispose();
402	      if (selected?.sessionId) {
403	        SessionDetailPanel.createOrShow(
404	          this.context,
405	          selected.sessionId,
406	          selected.sessionTitle,
407	          this.port,
408	          this.checkpointProvider,
409	          query || undefined,
410	        );
411	      }
412	    });
413	
414	    qp.onDidHide(() => {
415	      if (debounce) clearTimeout(debounce);
416	      qp.dispose();
417	    });
418	    qp.show();
419	  }
420	
421	  private async promptAndSpawnSession(): Promise<void> {
422	    // Pick agent — offer choices based on which agents have been used in this repo
423	    interface SessionStub { agent: string | null }
424	    let agentCli = DEFAULT_AGENT_CLI;
425	    try {
426	      const sessions = await httpGetJson<SessionStub[]>(`http://localhost:${this.port}/api/sessions`);
427	      const usedAgents = [...new Set(sessions.map((s) => s.agent).filter(Boolean) as string[])];
428	      const knownAgents = usedAgents.filter((a) => AGENT_CLI[a]);
429	      if (knownAgents.length > 1) {
430	        const picked = await vscode.window.showQuickPick(
431	          knownAgents.map((a) => ({ label: a, description: AGENT_CLI[a].bin })),
432	          { title: "Choose agent", ignoreFocusOut: true },
433	        );
434	        if (!picked) return;
435	        agentCli = AGENT_CLI[picked.label];
436	      } else if (knownAgents.length === 1) {
437	        agentCli = AGENT_CLI[knownAgents[0]];
438	      }
439	    } catch { /* use default */ }
440	
441	    const prompt = await vscode.window.showInputBox({
442	      title: `New ${agentCli.bin} Session`,
443	      prompt: `What do you want ${agentCli.bin} to do?`,
444	      placeHolder: "Describe the task…",
445	      ignoreFocusOut: true,
446	    });
447	    if (!prompt) return;
448	
449	    const name = await vscode.window.showInputBox({
450	      title: "Session Name (optional)",
451	      prompt: "Give this session a name, or press Enter to skip",
452	      placeHolder: "e.g. refactor auth module",
453	      ignoreFocusOut: true,
454	    });
455	
456	    const escaped = prompt.replace(/"/g, '\\"');
457	    const terminal = vscode.window.createTerminal({
458	      name: name || agentCli.bin,
459	      cwd: this.repoPath,
460	    });
461	    terminal.show();
462	    terminal.sendText(`${agentCli.bin} "${escaped}"`, true);
463	    if (name && agentCli.renameCmd) {
464	      setTimeout(() => terminal.sendText(`${agentCli.renameCmd} ${name}`, true), 2000);
465	    }
466	  }
467	
468	  private async ensureRepoRegistered(): Promise<void> {
469	    const current = await httpGetJson<unknown>(`http://localhost:${this.port}/api/repos/current`);
470	    if (current !== null) return; // already registered
471	
472	    const name = basename(this.repoPath);
473	    let remote = "";
474	    try {
475	      const { stdout } = await execFileAsync("git", ["-C", this.repoPath, "remote", "get-url", "origin"]);
476	      remote = stdout.trim();
477	    } catch { /* no remote configured */ }
478	
479	    console.log(`[Gossamer] registering repo: ${name} at ${this.repoPath}`);
480	    await httpPostJson(`http://localhost:${this.port}/api/repos`, {
481	      name,
482	      localPath: this.repoPath,
483	      remote,
484	    });
485	  }
486	
487	  private watchGitBranch() {
488	    const gitDir = join(this.repoPath, ".git");
489	    try {
490	      this.watcher = watch(gitDir, { recursive: false }, (_event, filename) => {
491	        // The server polls shadows every 5s already; this is just a hint for future use
492	        if (filename === "packed-refs" || (filename ?? "").startsWith("refs/")) {
493	          // Server handles re-indexing internally
494	        }
495	      });
496	    } catch { /* git dir unavailable */ }
497	  }
498	
499	  private getWebviewHtml(context: vscode.ExtensionContext): string {
500	    const webview   = this.panel.webview;
501	    const distUri   = vscode.Uri.joinPath(context.extensionUri, "dist", "webview");
502	    const scriptUri = webview.asWebviewUri(vscode.Uri.joinPath(distUri, "assets", "index.js"));
503	    const styleUri  = webview.asWebviewUri(vscode.Uri.joinPath(distUri, "assets", "index.css"));
504	    const nonce     = getNonce();
505	    const port      = this.port;
506	
507	    return `<!DOCTYPE html>
508	<html lang="en">
509	<head>
510	  <meta charset="UTF-8" />
511	  <meta http-equiv="Content-Security-Policy"
512	    content="default-src 'none'; style-src ${webview.cspSource} 'unsafe-inline'; script-src 'nonce-${nonce}'; connect-src http://localhost:${port} ws://localhost:${port}; img-src data: https: http:;" />
513	  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
514	  <link href="${styleUri}" rel="stylesheet" />
515	  <title>Gossamer</title>
516	</head>
517	<body>
518	  <div id="root"></div>
519	  <script nonce="${nonce}">window.__GOSSAMER_PORT__ = ${port};</script>
520	  <script nonce="${nonce}" type="module" src="${scriptUri}"></script>
521	</body>
522	</html>`;
523	  }
524	
525	  /** Dispose only the webview — server stays alive for quick restore. */
526	  private disposeWebviewOnly() {
527	    this.watcher?.close();
528	    this.disposables.forEach((d) => d.dispose());
529	    this.disposables = [];
530	    GossamerPanel.instance = undefined;
531	    this.panel.dispose();
532	  }
533	
534	  private cleanup(killServer: boolean) {
535	    if (killServer) {
536	      GossamerPanel.server?.kill();
537	      GossamerPanel.server = undefined;
538	      GossamerPanel.serverPort = undefined;
539	    }
540	    this.watcher?.close();
541	    this.disposables.forEach((d) => d.dispose());
542	    this.disposables = [];
543	    GossamerPanel.instance = undefined;
544	  }
545	}
546	
547	function getNonce(): string {
548	  const chars = "REDACTED";
549	  return Array.from({ length: 32 }, () =>
550	    chars[Math.floor(Math.random() * chars.length)],
551	  ).join("");
552	}
