85	export class CheckpointTreeProvider
86	  implements vscode.TreeDataProvider<CheckpointTreeItem>
87	{
88	  private _onDidChangeTreeData = new vscode.EventEmitter<void>();
89	  readonly onDidChangeTreeData = this._onDidChangeTreeData.event;
90	
91	  private sessionCheckpoints: Checkpoint[] = [];
92	  private branchCheckpoints: Checkpoint[] = [];
93	  private currentBranch: string | null = null;
94	  private currentPort: number | null = null;
95	  private currentRepoPath: string = "";
96	
97	  async setSession(sessionId: string, port: number): Promise<void> {
98	    this.currentPort = port;
99	
100	    // Fetch session info and checkpoints in parallel.
101	    const [allSessionCheckpoints, sessionInfo] = await Promise.all([
102	      fetchJson<Checkpoint[]>(
103	        `http://localhost:${port}/api/v2/sessions/${encodeURIComponent(sessionId)}/checkpoints`,
104	      ).catch(() => [] as Checkpoint[]),
105	      fetchJson<{ cwd: string; repoRoot: string | null; branch: string | null; updatedAt: string; isLive: boolean }>(
106	        `http://localhost:${port}/api/sessions/${encodeURIComponent(sessionId)}`,
107	      ).catch(() => ({ cwd: "", repoRoot: null, branch: null, updatedAt: "", isLive: false })),
108	    ]);
109	
110	    // Prefer repoRoot (the server's known local path for this repo) over the
111	    // session's stored cwd, which may be from a different machine or empty
112	    // (e.g. when the first event is a permission-mode event with no cwd).
113	    const repoPath = sessionInfo.repoRoot ?? sessionInfo.cwd;
114	    if (repoPath) this.currentRepoPath = repoPath;
115	
116	    // For completed sessions, restrict "Session" to checkpoints that were created
117	    // during the agent's active run (at or before the last log event, plus a small
118	    // buffer for indexing lag). Post-session commits tagged to the same session ID
119	    // by Entire are excluded here and will appear in Branch History instead.
120	    // Skip the filter when updatedAt is missing or clearly invalid (e.g. epoch
121	    // fallback from sessions whose LogEvents haven't been indexed yet).
122	    let sessionCheckpoints = allSessionCheckpoints;
123	    const updatedMs = sessionInfo.updatedAt ? new Date(sessionInfo.updatedAt).getTime() : 0;
124	    if (!sessionInfo.isLive && updatedMs > 1_000_000_000_000) {
125	      const cutoff = new Date(updatedMs + 2 * 60 * 1000);
126	      sessionCheckpoints = allSessionCheckpoints.filter(
127	        (cp) => !cp.createdAt || new Date(cp.createdAt) <= cutoff,
128	      );
129	    }
130	
131	    // Deduplicate branch history against session checkpoints so each commit
132	    // appears in exactly one section.
133	    const sessionIds = new Set(sessionCheckpoints.map((cp) => cp.checkpointId));
134	
135	    let branchCheckpoints: Checkpoint[] = [];
136	    try {
137	      if (repoPath && sessionInfo.branch) {
138	        this.currentBranch = sessionInfo.branch;
139	        const log = await fetchJson<{ entries: BranchLogEntry[] }>(
140	          `http://localhost:${port}/api/branch-log?localPath=${encodeURIComponent(repoPath)}&branch=${encodeURIComponent(sessionInfo.branch)}`,
141	        );
142	
143	        // Build a message map from ALL branch-log entries before dedup, so session
144	        // checkpoints missing a commit message can fall back to the branch-log value.
145	        const branchMessageMap = new Map<string, string>();
146	        const branchHashMap    = new Map<string, string>();
147	        for (const entry of log.entries) {
148	          if (entry.commitMessage) branchMessageMap.set(entry.checkpointId, entry.commitMessage);
149	          if (entry.commitHash)    branchHashMap.set(entry.checkpointId, entry.commitHash);
150	        }
151	
152	        // Enrich session checkpoints that have a null commit message.
153	        sessionCheckpoints = sessionCheckpoints.map((cp) => ({
154	          ...cp,
155	          commitMessage: cp.commitMessage ?? branchMessageMap.get(cp.checkpointId) ?? null,
156	          commitHash:    cp.commitHash    ?? branchHashMap.get(cp.checkpointId)    ?? null,
157	        }));
158	
159	        const seen = new Set<string>(sessionIds);
160	        for (const entry of log.entries) {
161	          if (!seen.has(entry.checkpointId)) {
162	            seen.add(entry.checkpointId);
163	            branchCheckpoints.push({
164	              checkpointId:  entry.checkpointId,
165	              createdAt:     entry.createdAt,
166	              filesTouched:  entry.filesTouched,
167	              summary:       entry.summary,
168	              commitMessage: entry.commitMessage,
169	              commitHash:    entry.commitHash,
170	            });
171	          }
172	        }
173	      }
174	    } catch { /* branch-log unavailable or repo not registered */ }
175	
176	    this.sessionCheckpoints = sessionCheckpoints;
177	    this.branchCheckpoints  = branchCheckpoints;
178	    if (branchCheckpoints.length === 0) this.currentBranch = null;
179	    this._onDidChangeTreeData.fire();
180	  }
