182	  getTreeItem(element: CheckpointTreeItem): vscode.TreeItem {
183	    if (element.kind === "group") {
184	      const item = new vscode.TreeItem(element.label, vscode.TreeItemCollapsibleState.Expanded);
185	      item.iconPath = new vscode.ThemeIcon("history");
186	      return item;
187	    }
188	    if (element.kind === "checkpoint") {
189	      const cp      = element.cp;
190	      const shortId = cp.checkpointId.slice(0, 8);
191	      const msg     = cp.commitMessage;
192	      const label   = msg
193	        ? (msg.length > 60 ? msg.slice(0, 59) + "…" : msg)
194	        : shortId;
195	
196	      const collapsible = element.index === 0
197	        ? vscode.TreeItemCollapsibleState.Expanded
198	        : vscode.TreeItemCollapsibleState.Collapsed;
199	      const item = new vscode.TreeItem(label, collapsible);
200	
201	      const commitShort = cp.commitHash ? cp.commitHash.slice(0, 8) : null;
202	      item.description  = commitShort ? `${shortId} · ${commitShort}` : shortId;
203	
204	      const tooltip = new vscode.MarkdownString("", true);
205	      tooltip.appendMarkdown(`**Checkpoint:** \`${cp.checkpointId}\`\n\n`);
206	      if (cp.commitHash) tooltip.appendMarkdown(`**Commit:** \`${cp.commitHash}\`\n\n`);
207	      if (msg) tooltip.appendMarkdown(msg);
208	      item.tooltip  = tooltip;
209	      item.iconPath = new vscode.ThemeIcon("git-commit");
210	      item.contextValue = "checkpoint";
211	      return item;
212	    }
213	    if (element.kind === "summary") {
214	      const item = new vscode.TreeItem("summary.txt", vscode.TreeItemCollapsibleState.None);
215	      item.iconPath = new vscode.ThemeIcon("note");
216	      item.tooltip = element.text;
217	      item.command = {
218	        command: "gossamer.showCheckpointSummary",
219	        title: "Show Summary",
220	        arguments: [element.checkpointId, element.text],
221	      };
222	      return item;
223	    }
224	    if (element.kind === "dir") {
225	      const item = new vscode.TreeItem(element.label, vscode.TreeItemCollapsibleState.Expanded);
226	      item.resourceUri = vscode.Uri.file(element.absPath);
227	      return item;
228	    }
229	    // file
230	    const item = new vscode.TreeItem(element.name, vscode.TreeItemCollapsibleState.None);
231	    item.resourceUri = vscode.Uri.file(element.absPath);
232	    item.tooltip = element.fullPath;
233	    item.command = {
234	      command: "gossamer.showCheckpointDiff",
235	      title: "Show Diff",
236	      arguments: [element.checkpointId, element.fullPath, element.port],
237	    };
238	    return item;
239	  }
