      const msg = JSON.parse(raw.toString()) as { type: string; data?: string; cols?: number; rows?: number };
      if (msg.type === "data" && msg.data) term.write(msg.data);
      if (msg.type === "resize" && msg.cols && msg.rows) term.resize(msg.cols, msg.rows);
