      data: {
        ...(status !== undefined ? { status } : {}),
        ...(subSessionId !== undefined ? { subSessionId } : {}),
      },
    });
    res.json({ id: updated.id, status: updated.status, subSessionId: updated.subSessionId });
  } catch (err) {
    res.status(500).json({ error: String(err) });
  }
});

